        return n >= 1 ? 1 : 0;
    }

    const memo = new Map();

    function countNumbersWithDepth(x, remainingDepth, isTight, bits) {
        if (remainingDepth === 0) {
            return x === 1 ? 1 : 0;
        }
        if (bits === 0) {
            return 0;
        }

        const key = `${x}_${remainingDepth}_${isTight}_${bits}`;
        if (memo.has(key)) {
            return memo.get(key);
        }

        let maxBit = isTight ? ((n >> (bits - 1)) & 1) : 1;
        let total = 0;

        for (let b = 0; b <= maxBit; b++) {
            const newIsTight = isTight && (b === maxBit);
            const newX = x + b;
            const newBits = bits - 1;
            total += countNumbersWithDepth(newX, remainingDepth - (b === 1 ? 1 : 0), newIsTight, newBits);
        }

        memo.set(key, total);
